const req = $('normalize_input').first().json;
const foreign = $('fetch_ebird_foreign').first().json || {};
const history = $('fetch_elurikkus_history').first().json || {};
const recent = $('fetch_estonia_recent').first().json || {};
const weather = $('fetch_weather').first().json || {};
const priority = ['latvia', 'lithuania', 'belarus', 'poland', 'russia'];
const enabled = priority.filter((country) => ({ latvia: req.useLatvia, lithuania: req.useLithuania, belarus: req.useBelarus, poland: req.usePoland, russia: req.useRussia })[country]);
const rows = (Array.isArray(foreign.rows) ? foreign.rows : []).map((row) => ({
  country: String(row.country || '').toLowerCase(),
  daysAgo: Number(row.daysAgo || 0),
  distanceToEstoniaKm: Number(row.distanceToEstoniaKm || 0),
  recordCount: Number(row.recordCount || 0),
  lat: Number(row.lat || 0),
  lon: Number(row.lon || 0),
  hotspotName: String(row.hotspotName || row.name || '').trim(),
  countyOrParish: String(row.countyOrParish || row.region || '').trim(),
  habitatCue: String(row.habitatCue || '').trim(),
})).filter((row) => row.country && (enabled.includes(row.country) || row.country === 'finland'));
const countryScores = { latvia: 0, lithuania: 0, belarus: 0, poland: 0, russia: 0 };
for (const country of priority) {
  const score = rows.filter((row) => row.country === country).reduce((sum, row) => sum + Math.max(0, 20 - row.daysAgo * 2.5) + Math.max(0, 20 - row.distanceToEstoniaKm / 80) + Math.min(30, row.recordCount * 3) + ((row.lat !== 0 || row.lon !== 0) ? 10 : 0), 0);
  countryScores[country] = Math.max(0, Math.min(100, Math.round(score)));
}
const finlandContextOnly = Math.max(0, Math.min(100, Math.round(rows.filter((row) => row.country === 'finland').reduce((sum, row) => sum + Math.min(25, row.recordCount * 2), 0))));
const primary = enabled.map((country) => ({ country, score: countryScores[country] || 0 })).sort((a, b) => b.score - a.score)[0] || { country: 'latvia', score: 0 };
const springFitScore = Math.max(0, Math.min(100, Math.round(Number(history.springFitScore || 0) * 0.7 + Math.min(30, (Array.isArray(history.historicalHotspots) ? history.historicalHotspots.length : 0) * 6))));
const windSupportScore = Math.max(0, Math.min(100, Math.round(Number(weather.windSupportScore || 0))));
const externalPressureScore = Math.max(0, Math.min(100, Math.round(enabled.reduce((sum, country, index) => sum + (countryScores[country] || 0) * Math.max(1, 5 - index), 0) / Math.max(1, enabled.reduce((sum, _country, index) => sum + Math.max(1, 5 - index), 0)))));
const routeVector = primary.score > 0 ? (primary.country + '->estonia ' + (String(weather.windDirection || 'variable').trim() || 'variable')) : ('regional_estonia ' + (String(weather.windDirection || 'variable').trim() || 'variable'));
const bestEntryZone = primary.country === 'latvia' ? 'Southwest Estonia' : primary.country === 'lithuania' ? 'South Estonia' : primary.country === 'belarus' ? 'Southeast Estonia' : primary.country === 'poland' ? 'West Estonia' : primary.country === 'russia' ? 'East Estonia' : 'West Estonia';
const alreadyMissedRisk = recent.alreadyPassed ? 'high' : ((recent.alreadyPresent || Number(recent.recentCount7d || 0) > 10) ? 'medium' : 'low');
const candidates = [
  ...(Array.isArray(history.historicalHotspots) ? history.historicalHotspots : []).map((row) => ({
    name: String(row.name || '').trim(), countyOrParish: String(row.countyOrParish || '').trim(), lat: Number(row.lat || 0), lon: Number(row.lon || 0), confidence: Math.max(0, Math.min(100, Math.round(Number(row.confidence || 0)))), habitatCue: String(row.habitatCue || '').trim(), reason: String(row.reason || '').trim(),
  })),
  ...rows.filter((row) => row.lat !== 0 || row.lon !== 0).map((row) => ({
    name: row.hotspotName || (row.country + ' migration hotspot'), countyOrParish: row.countyOrParish || row.country, lat: row.lat, lon: row.lon, confidence: Math.max(0, Math.min(100, Math.round(50 + row.recordCount * 4 - row.daysAgo * 3))), habitatCue: row.habitatCue || 'Migration stopover habitat', reason: row.country + ' pressure ' + row.recordCount + ' recent records within ' + row.distanceToEstoniaKm + ' km',
  })),
].filter((point) => point.name && (point.lat !== 0 || point.lon !== 0));
const seen = new Set();
const topPredictedPoints = candidates.filter((point) => { const key = point.name + '|' + point.lat + '|' + point.lon; if (seen.has(key)) return false; seen.add(key); return true; }).sort((a, b) => Number(b.confidence || 0) - Number(a.confidence || 0)).slice(0, Math.max(1, Number(req.outputCount || 5))).map((point, index) => ({ rank: index + 1, name: point.name, countyOrParish: point.countyOrParish || bestEntryZone, lat: Number(point.lat || 0), lon: Number(point.lon || 0), confidence: Math.max(0, Math.min(100, Math.round(Number(point.confidence || 0)))), eta: index === 0 ? '24-48h' : (index < 3 ? '48-72h' : '3-5d'), searchRadiusKm: Math.max(1, Math.round(Number(req.hotspotRadiusKm || 5))), habitatCue: point.habitatCue || 'Migration habitat', reason: point.reason || ('Weighted by ' + primary.country + ' source pressure and spring fit') }));
const fallback = topPredictedPoints.length ? topPredictedPoints : [{ rank: 1, name: req.speciesName + ' primary hotspot candidate', countyOrParish: bestEntryZone, lat: 58.6, lon: 24.8, confidence: Math.max(25, Math.round((externalPressureScore + springFitScore + windSupportScore) / 3)), eta: '2-4d', searchRadiusKm: Math.max(1, Math.round(Number(req.hotspotRadiusKm || 5))), habitatCue: 'Check exact coastal and wetland hotspots', reason: 'No precise hotspot coordinates returned from upstream sources; using exact-point fallback placeholder' }];
const deterministicSummary = req.requestType === 'prediction' ? '' : (req.speciesName + ': strongest spring driver is ' + primary.country + ' pressure, spring fit is ' + springFitScore + '/100, wind support is ' + windSupportScore + '/100.');
const foreignSightingsSummary = rows.slice(0, 8).map((row) => ({ country: row.country, hotspotName: row.hotspotName || '', countyOrParish: row.countyOrParish, daysAgo: row.daysAgo, distanceToEstoniaKm: row.distanceToEstoniaKm, recordCount: row.recordCount, lat: row.lat, lon: row.lon, habitatCue: row.habitatCue }));
const historicalHotspotSummary = (Array.isArray(history.historicalHotspots) ? history.historicalHotspots : []).slice(0, 8).map((row) => ({ name: String(row.name || '').trim(), countyOrParish: String(row.countyOrParish || '').trim(), lat: Number(row.lat || 0), lon: Number(row.lon || 0), confidence: Number(row.confidence || 0), habitatCue: String(row.habitatCue || '').trim(), reason: String(row.reason || '').trim() }));
const recentEstoniaPresenceSummary = { alreadyPresent: Boolean(recent.alreadyPresent), alreadyPassed: Boolean(recent.alreadyPassed), recentCount7d: Number(recent.recentCount7d || 0), recentCount30d: Number(recent.recentCount30d || 0) };
const weatherSummary = { windSupportScore: windSupportScore, windDirection: String(weather.windDirection || ''), windSpeed: Number(weather.windSpeed || 0), precipitation: Number(weather.precipitation || 0) };
const openAIAnalysisInput = { speciesKey: req.speciesKey, speciesName: req.speciesName, latinName: req.latinName, countryScores: { latvia: countryScores.latvia, lithuania: countryScores.lithuania, belarus: countryScores.belarus, poland: countryScores.poland, russia: countryScores.russia, ...(req.useFinlandContextOnly ? { finlandContextOnly } : {}) }, externalPressureScore, springFitScore, windSupportScore, routeVector, bestEntryZone, alreadyMissedRisk, foreignSightingsSummary, historicalHotspotSummary, recentEstoniaPresenceSummary, weatherSummary, currentTopPredictedPoints: fallback };
return [{ json: { speciesKey: req.speciesKey, speciesName: req.speciesName, generatedAt: new Date().toISOString(), externalPressureScore, springFitScore, windSupportScore, routeVector, bestEntryZone, alreadyMissedRisk, countryScores: { latvia: countryScores.latvia, lithuania: countryScores.lithuania, belarus: countryScores.belarus, poland: countryScores.poland, russia: countryScores.russia, ...(req.useFinlandContextOnly ? { finlandContextOnly } : {}) }, topPredictedPoints: fallback, analysisFallbackUsed: false, ...(deterministicSummary ? { insightSummary: deterministicSummary } : {}), rawResearchPayload: { request: { requestType: req.requestType, speciesKey: req.speciesKey, speciesName: req.speciesName, latinName: req.latinName, predictionMode: req.predictionMode, summaryStyle: req.summaryStyle, summaryMaxLength: Number(req.summaryMaxLength || 450), enableOpenAISummary: Boolean(req.enableOpenAISummary) }, normalizedSources: { foreignSightings: rows.map((row) => ({ country: row.country, daysAgo: row.daysAgo, distanceToEstoniaKm: row.distanceToEstoniaKm, recordCount: row.recordCount, lat: row.lat, lon: row.lon })), elurikkusHistory: { springFitScore: Number(history.springFitScore || 0), historicalHotspots: Array.isArray(history.historicalHotspots) ? history.historicalHotspots : [], habitatHints: Array.isArray(history.habitatHints) ? history.habitatHints : [], arrivalWindow: String(history.arrivalWindow || '') }, estoniaRecent: recentEstoniaPresenceSummary, weather: weatherSummary }, openAIAnalysisInput }, openAIAnalysisInput } }];

const base = $('calculate_species_parameters').first().json || {};
const raw = $json || {};
const content = String((((raw || {}).choices || [])[0] || {}).message?.content || '').trim();
if (!content) return [{ json: { ...base, analysisFallbackUsed: true } }];
let parsed;
try { parsed = JSON.parse(content); } catch (_error) { return [{ json: { ...base, analysisFallbackUsed: true } }]; }
const allowed = new Set((Array.isArray(base.topPredictedPoints) ? base.topPredictedPoints : []).map((point) => String(point.name || '') + '|' + Number(point.lat || 0) + '|' + Number(point.lon || 0)));
const reranked = Array.isArray(parsed.rerankedTopPredictedPoints) ? parsed.rerankedTopPredictedPoints : [];
for (const point of reranked) {
  const key = String(point?.name || '') + '|' + Number(point?.lat || 0) + '|' + Number(point?.lon || 0);
  if (!allowed.has(key)) return [{ json: { ...base, analysisFallbackUsed: true } }];
}
return [{ json: { ...base, parsedOpenAIAnalysis: parsed, analysisFallbackUsed: false } }];

const base = $json || {};
const analysis = base.parsedOpenAIAnalysis;
if (!analysis || typeof analysis !== 'object') return [{ json: { ...base, analysisFallbackUsed: true } }];
const openaiAnalysis = {
  analysisVersion: String(analysis.analysisVersion || 'openai_v1'),
  insightSummary: String(analysis.insightSummary || base.insightSummary || ''),
  confidenceNote: String(analysis.confidenceNote || ''),
  warnings: Array.isArray(analysis.warnings) ? analysis.warnings.map((warning) => String(warning || '').trim()).filter(Boolean) : [],
  rerankedTopPredictedPoints: Array.isArray(analysis.rerankedTopPredictedPoints) ? analysis.rerankedTopPredictedPoints : [],
  consistencyChecks: analysis.consistencyChecks || { routeLooksPlausible: false, timingLooksPlausible: false, weatherLooksSupportive: false, foreignPressureMatchesNarrative: false },
};
return [{ json: { ...base, insightSummary: openaiAnalysis.insightSummary || base.insightSummary || '', analysisVersion: openaiAnalysis.analysisVersion, analysisFallbackUsed: false, confidenceNote: openaiAnalysis.confidenceNote, warnings: openaiAnalysis.warnings, rerankedTopPredictedPoints: openaiAnalysis.rerankedTopPredictedPoints, consistencyChecks: openaiAnalysis.consistencyChecks, openaiAnalysis } }];
